mapper.insert:
    INSERT INTO MOVIE
	( MOVIE_ID
	, POSTER_URL
	, TITLE
	, MOVIE_RATING
	, OPEN_DATE
	, OPEN_COUNTRY
	, RUNNING_TIME
	, INTRODUCE
	, SYSNOPSIS
	, ORIGINAL_TITLE
	, STATE
	, "LANGUAGE"
	, BUDGET
	, PROFIT)
	VALUES
	( 'MV-' || TO_CHAR(SYSDATE, 'YYYYMMDD-') || LPAD(SEQ_MOVIE_PK.NEXTVAL, 6, '0')
	, #{posterUrl}
	, #{title}
	, #{movieRating}
	, TO_DATE(#{openDate}, 'YYYY-MM-DD')
	, #{openCountry}
	, #{runningTime}
	, #{introduce}
	, #{sysnopsis}
	, #{originalTitle}
	, #{state}
	, #{language}
	, #{budget}
	, #{profit})

mapper.update:
        UPDATE MOVIE
		   SET POSTER_URL = #{posterUrl}
		     , TITLE = #{title}
		     , MOVIE_RATING = #{movieRating}
		     , OPEN_DATE = #{openDate}
		     , OPEN_COUNTRY = #{openCountry}
		     , RUNNING_TIME = #{runningTime}
		     , INTRODUCE = #{introduce}
		     , SYSNOPSIS = #{sysnopsis}
		     , ORIGINAL_TITLE = #{originalTitle}
		     , STATE = #{state}
		     , "LANGUAGE" = #{language}
		     , BUDGET = #{budget}
		     , PROFIT = #{profit}
		WHERE MOVIE_ID = #{movieId}
